// services/cartSync.ts
import useAuthStore from '../store/authStore';
import useCartStore from '../store/cartStore';
import { api } from './api';

async function syncCartAfterLogin() {
  const { token, user } = useAuthStore.getState();
  const { items: localItems, clearCart, addItem } = useCartStore.getState();

  if (!token || !user) return;

  try {
    // 1. Récupérer le panier distant
    const remoteCart = await api.get('/cart');

    // 2. Fusionner
    const mergedItems = [];
    const remoteMap = new Map(remoteCart.map(item => [
      `${item.id}-${item.selectedSize || ''}`, 
      item
    ]));

    for (const localItem of localItems) {
      const key = `${localItem.id}-${localItem.selectedSize || ''}`;
      if (remoteMap.has(key)) {
        const remoteItem = remoteMap.get(key);
        remoteItem.quantity += localItem.quantity;
        remoteMap.set(key, remoteItem);
      } else {
        mergedItems.push(localItem);
      }
    }

    // Ajouter les articles distants restants
    const finalCart = [...Array.from(remoteMap.values()), ...mergedItems];

    // 3. Envoyer au backend
    await api.put('/cart', { items: finalCart });

    // 4. Remplacer le panier local
    clearCart();
    finalCart.forEach(item => addItem(item, item.quantity));

  } catch (error) {
    console.error('Erreur lors de la synchronisation du panier', error);
  }
}

